(window.webpackJsonp=window.webpackJsonp||[]).push([[910],{860:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">code</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> decrypt = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">code, k</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> len=code.length\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getAfterSum</span>(<span class=\\"hljs-params\\">curIdx,k</span>)</span>{\\n        <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">let</span> i=(curIdx+<span class=\\"hljs-number\\">1</span>) % len\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">0</span>;step&lt;k;i=(i+<span class=\\"hljs-number\\">1</span>) % len,step++){\\n            sum+=code[i]\\n        }\\n        <span class=\\"hljs-keyword\\">return</span> sum\\n    }\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getBeforeSum</span>(<span class=\\"hljs-params\\">curIdx,k</span>)</span>{\\n        <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">let</span> i=(curIdx<span class=\\"hljs-number\\">-1</span> + len) % len\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">0</span>;step&lt;-k;i=(i<span class=\\"hljs-number\\">-1</span>+len) % len,step++){\\n            sum+=code[i]\\n        }\\n        <span class=\\"hljs-keyword\\">return</span> sum\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">if</span>(k===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Array</span>(len).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(k&gt;<span class=\\"hljs-number\\">0</span>){\\n            res[i]=getAfterSum(i,k)\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            res[i]=getBeforeSum(i,k)\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"defuse-the-bomb","hasThinking":false,"content":"<p>\u4f60\u6709\u4e00\u4e2a\u70b8\u5f39\u9700\u8981\u62c6\u9664\uff0c\u65f6\u95f4\u7d27\u8feb\uff01\u4f60\u7684\u60c5\u62a5\u5458\u4f1a\u7ed9\u4f60\u4e00\u4e2a\u957f\u5ea6\u4e3a\xa0<code>n</code>\xa0\u7684\xa0<strong>\u5faa\u73af</strong>\xa0\u6570\u7ec4\xa0<code>code</code>\xa0\u4ee5\u53ca\u4e00\u4e2a\u5bc6\u94a5\xa0<code>k</code>\xa0\u3002</p>\\n\\n<p>\u4e3a\u4e86\u83b7\u5f97\u6b63\u786e\u7684\u5bc6\u7801\uff0c\u4f60\u9700\u8981\u66ff\u6362\u6389\u6bcf\u4e00\u4e2a\u6570\u5b57\u3002\u6240\u6709\u6570\u5b57\u4f1a\xa0<strong>\u540c\u65f6</strong>\xa0\u88ab\u66ff\u6362\u3002</p>\\n\\n<ul>\\n\\t<li>\u5982\u679c\xa0<code>k > 0</code>\xa0\uff0c\u5c06\u7b2c\xa0<code>i</code>\xa0\u4e2a\u6570\u5b57\u7528 <strong>\u63a5\u4e0b\u6765</strong>\xa0<code>k</code>\xa0\u4e2a\u6570\u5b57\u4e4b\u548c\u66ff\u6362\u3002</li>\\n\\t<li>\u5982\u679c\xa0<code>k < 0</code>\xa0\uff0c\u5c06\u7b2c\xa0<code>i</code>\xa0\u4e2a\u6570\u5b57\u7528 <strong>\u4e4b\u524d</strong>\xa0<code>k</code>\xa0\u4e2a\u6570\u5b57\u4e4b\u548c\u66ff\u6362\u3002</li>\\n\\t<li>\u5982\u679c\xa0<code>k == 0</code>\xa0\uff0c\u5c06\u7b2c\xa0<code>i</code>\xa0\u4e2a\u6570\u5b57\u7528\xa0<code>0</code>\xa0\u66ff\u6362\u3002</li>\\n</ul>\\n\\n<p>\u7531\u4e8e\xa0<code>code</code>\xa0\u662f\u5faa\u73af\u7684\uff0c\xa0<code>code[n-1]</code>\xa0\u4e0b\u4e00\u4e2a\u5143\u7d20\u662f\xa0<code>code[0]</code>\xa0\uff0c\u4e14\xa0<code>code[0]</code>\xa0\u524d\u4e00\u4e2a\u5143\u7d20\u662f\xa0<code>code[n-1]</code>\xa0\u3002</p>\\n\\n<p>\u7ed9\u4f60 <strong>\u5faa\u73af</strong>\xa0\u6570\u7ec4\xa0<code>code</code>\xa0\u548c\u6574\u6570\u5bc6\u94a5\xa0<code>k</code>\xa0\uff0c\u8bf7\u4f60\u8fd4\u56de\u89e3\u5bc6\u540e\u7684\u7ed3\u679c\u6765\u62c6\u9664\u70b8\u5f39\uff01</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>code = [5,7,1,4], k = 3\\n<b>\u8f93\u51fa\uff1a</b>[12,10,16,13]\\n<b>\u89e3\u91ca\uff1a</b>\u6bcf\u4e2a\u6570\u5b57\u90fd\u88ab\u63a5\u4e0b\u6765 3 \u4e2a\u6570\u5b57\u4e4b\u548c\u66ff\u6362\u3002\u89e3\u5bc6\u540e\u7684\u5bc6\u7801\u4e3a [7+1+4, 1+4+5, 4+5+7, 5+7+1]\u3002\u6ce8\u610f\u5230\u6570\u7ec4\u662f\u5faa\u73af\u8fde\u63a5\u7684\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>code = [1,2,3,4], k = 0\\n<b>\u8f93\u51fa\uff1a</b>[0,0,0,0]\\n<b>\u89e3\u91ca\uff1a</b>\u5f53 k \u4e3a 0 \u65f6\uff0c\u6240\u6709\u6570\u5b57\u90fd\u88ab 0 \u66ff\u6362\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>code = [2,4,9,3], k = -2\\n<b>\u8f93\u51fa\uff1a</b>[12,5,6,13]\\n<b>\u89e3\u91ca\uff1a</b>\u89e3\u5bc6\u540e\u7684\u5bc6\u7801\u4e3a [3+9, 2+3, 4+2, 9+4] \u3002\u6ce8\u610f\u5230\u6570\u7ec4\u662f\u5faa\u73af\u8fde\u63a5\u7684\u3002\u5982\u679c k \u662f\u8d1f\u6570\uff0c\u90a3\u4e48\u548c\u4e3a <strong>\u4e4b\u524d</strong> \u7684\u6570\u5b57\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == code.length</code></li>\\n\\t<li><code>1 <= n\xa0<= 100</code></li>\\n\\t<li><code>1 <= code[i] <= 100</code></li>\\n\\t<li><code>-(n - 1) <= k <= n - 1</code></li>\\n</ul>\\n","title":"1652. \u62c6\u70b8\u5f39","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1652"}')}}]);